class ElasticsearchLogHandler(logging.Handler):
    def __init__(
        self,
        es_client: Elasticsearch,
        index_prefix: str = "logs",
        service: str = "centralized-platform",
        environment: str = "dev",
    ):
        super().__init__()
        self.es_client = es_client
        self.index_prefix = index_prefix
        self.service = service
        self.environment = environment
        self.hostname = socket.gethostname()

    def emit(self, record: logging.LogRecord) -> None:
        try:
            ts = datetime.fromtimestamp(record.created, tz=timezone.utc)
            index_name = f"{self.index_prefix}-{ts.strftime('%Y.%m.%d')}"
            extra = self._extract_extra(record)
            document = {
                "@timestamp": ts.isoformat(),
                "level": record.levelname,
                "logger": record.name,
                "message": record.getMessage(),
                "service": self.service,
                "host": self.hostname,
                "environment": self.environment,
                "module": record.module,
                "function": record.funcName,
                "line": record.lineno,
                "extra": extra,
            }
            self.es_client.index(index=index_name, document=document)
        except Exception:
            self.handleError(record)

    @staticmethod
    def _extract_extra(record: logging.LogRecord) -> Dict[str, Any]:
        standard = {
            "name",
            "msg",
            "args",
            "levelname",
            "levelno",
            "pathname",
            "filename",
            "module",
            "exc_info",
            "exc_text",
            "stack_info",
            "lineno",
            "funcName",
            "created",
            "msecs",
            "relativeCreated",
            "thread",
            "threadName",
            "processName",
            "process",
            "message",
        }
        extra = {}
        for key, value in record.__dict__.items():
            if key not in standard:
                try:
                    extra[key] = value if isinstance(value, (str, int, float, bool, list, dict, type(None))) else str(value)
                except Exception:
                    extra[key] = str(value)
        return extra


def setup_logging(
    es_client: Elasticsearch,
    service: str = "centralized-platform",
    environment: str = "dev",
    level: int = logging.INFO,
) -> logging.Logger:
    logger = logging.getLogger(service)
    logger.setLevel(level)
    logger.propagate = False

    if not logger.handlers:
        stream_handler = logging.StreamHandler(sys.stdout)
        stream_handler.setLevel(level)
        stream_handler.setFormatter(
            logging.Formatter("%(asctime)s %(levelname)s %(name)s %(message)s")
        )

        es_handler = ElasticsearchLogHandler(
            es_client=es_client,
            index_prefix="logs",
            service=service,
            environment=environment,
        )
        es_handler.setLevel(level)

        logger.addHandler(stream_handler)
        logger.addHandler(es_handler)

    return logger


